// Shared URL-state helper for list views (artifacts, etc.).
// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
// filters.*) while preserving any unrelated keys, including ?back=.

export type GroupBy = 'folder' | 'prefix' | 'mediaType'

const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort'])
const FILTER_PREFIX = 'filter.'

export interface ListURLState {
	q: string
	mediaType: string | null
	groupBy: GroupBy
	sort: string | null
	filters: Record<string, string>
}

export const DEFAULT_GROUP_BY: GroupBy = 'folder'

function parseGroupBy(raw: string | null): GroupBy {
	if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder') return raw
	return DEFAULT_GROUP_BY
}

export function readState(params: URLSearchParams): ListURLState {
	const filters: Record<string, string> = {}
	for (const [k, v] of params.entries()) {
		if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v
	}
	return {
		q: params.get('q') ?? '',
		mediaType: params.get('mediaType'),
		groupBy: parseGroupBy(params.get('groupBy')),
		sort: params.get('sort'),
		filters
	}
}

// writeState mutates a copy of `params` with the patch applied. Unrelated
// keys (including `back`) are preserved. Empty/null values delete the key.
export function writeState(
	params: URLSearchParams,
	patch: Partial<ListURLState>
): URLSearchParams {
	const next = new URLSearchParams(params)

	if ('q' in patch) {
		if (patch.q) next.set('q', patch.q)
		else next.delete('q')
	}
	if ('mediaType' in patch) {
		if (patch.mediaType) next.set('mediaType', patch.mediaType)
		else next.delete('mediaType')
	}
	if ('groupBy' in patch) {
		if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy)
		else next.delete('groupBy')
	}
	if ('sort' in patch) {
		if (patch.sort) next.set('sort', patch.sort)
		else next.delete('sort')
	}
	if ('filters' in patch && patch.filters) {
		// Replace only the filter.* keys; leave everything else intact.
		for (const k of Array.from(next.keys())) {
			if (k.startsWith(FILTER_PREFIX)) next.delete(k)
		}
		for (const [k, v] of Object.entries(patch.filters)) {
			if (v) next.set(FILTER_PREFIX + k, v)
		}
	}

	return next
}

// Build a back-href that captures the current pathname + relevant search.
export function backHref(pathname: string, params: URLSearchParams): string {
	const s = params.toString()
	return s ? `${pathname}?${s}` : pathname
}

export { KNOWN_KEYS, FILTER_PREFIX }

import { describe, it, expect } from 'vitest'
import { readState, writeState, backHref, DEFAULT_GROUP_BY } from './urlState'

describe('urlState.readState', () => {
	it('returns defaults for an empty URL', () => {
		const s = readState(new URLSearchParams(''))
		expect(s.q).toBe('')
		expect(s.mediaType).toBeNull()
		expect(s.groupBy).toBe(DEFAULT_GROUP_BY)
		expect(s.sort).toBeNull()
		expect(s.filters).toEqual({})
	})

	it('parses known keys and filter.* entries', () => {
		const s = readState(
			new URLSearchParams('q=foo&mediaType=text/markdown&groupBy=prefix&sort=title&filter.tag=v1')
		)
		expect(s.q).toBe('foo')
		expect(s.mediaType).toBe('text/markdown')
		expect(s.groupBy).toBe('prefix')
		expect(s.sort).toBe('title')
		expect(s.filters).toEqual({ tag: 'v1' })
	})

	it('falls back to default groupBy on unknown values', () => {
		const s = readState(new URLSearchParams('groupBy=nonsense'))
		expect(s.groupBy).toBe(DEFAULT_GROUP_BY)
	})
})

describe('urlState.writeState', () => {
	it('preserves unrelated keys, including back', () => {
		const next = writeState(new URLSearchParams('back=/x?y=1&other=keep'), { q: 'hi' })
		expect(next.get('back')).toBe('/x?y=1')
		expect(next.get('other')).toBe('keep')
		expect(next.get('q')).toBe('hi')
	})

	it('drops groupBy when it equals the default', () => {
		const next = writeState(new URLSearchParams('groupBy=prefix'), { groupBy: 'folder' })
		expect(next.has('groupBy')).toBe(false)
	})

	it('deletes keys when given empty/null values', () => {
		const next = writeState(new URLSearchParams('q=old&mediaType=x'), {
			q: '',
			mediaType: null
		})
		expect(next.has('q')).toBe(false)
		expect(next.has('mediaType')).toBe(false)
	})

	it('replaces filter.* entries atomically', () => {
		const next = writeState(new URLSearchParams('filter.a=1&filter.b=2&q=keep'), {
			filters: { c: '3' }
		})
		expect(next.has('filter.a')).toBe(false)
		expect(next.has('filter.b')).toBe(false)
		expect(next.get('filter.c')).toBe('3')
		expect(next.get('q')).toBe('keep')
	})
})

describe('urlState.backHref', () => {
	it('omits the trailing ? when there are no params', () => {
		expect(backHref('/x', new URLSearchParams(''))).toBe('/x')
	})
	it('joins path and params', () => {
		expect(backHref('/x', new URLSearchParams('q=1'))).toBe('/x?q=1')
	})
})

// Group derivations for the artifacts list page.
// Pure, regex-based; safe to run on every render.

export type GroupBy = 'folder' | 'prefix' | 'mediaType'

// folderOf("docs/helix/01-frame/prd.md") => "docs/helix/01-frame"
// folderOf("README.md") => "/"
const FOLDER_RE = /^(.*)\/[^/]+$/
export function folderOf(path: string): string {
	const m = path.match(FOLDER_RE)
	if (!m) return '/'
	return m[1] || '/'
}

// prefixOf("docs/helix/01-frame/prd.md") => "docs"
// prefixOf("/library/personas/x.md") => "library"
const PREFIX_RE = /^\/?([^/]+)/
export function prefixOf(path: string): string {
	const m = path.match(PREFIX_RE)
	return m ? m[1] : ''
}

// Workflow stage derivation. Matches the canonical HELIX-style numbered
// stage segment (e.g. 01-frame, 02-design) anywhere in the path. Returns
// the bare stage name lowercased, or null when no stage segment is found.
const STAGE_RE = /(?:^|\/)\d{2}-([a-z][a-z0-9-]*)(?:\/|$)/i
export function workflowStageOf(path: string): string | null {
	const m = path.match(STAGE_RE)
	return m ? m[1].toLowerCase() : null
}

// Whether the workflow-stage axis should be shown for the given paths.
// The axis is hidden when no artifact in view has a derivable stage.
export function axisAvailable(paths: Iterable<string>): boolean {
	for (const p of paths) {
		if (workflowStageOf(p) !== null) return true
	}
	return false
}

export interface Groupable {
	path: string
	mediaType: string
}

export function groupKey(item: Groupable, by: GroupBy): string {
	switch (by) {
		case 'folder':
			return folderOf(item.path)
		case 'prefix':
			return prefixOf(item.path)
		case 'mediaType':
			return item.mediaType || 'unknown'
	}
}

export function groupItems<T extends Groupable>(
	items: T[],
	by: GroupBy
): { key: string; items: T[] }[] {
	const buckets = new Map<string, T[]>()
	for (const it of items) {
		const k = groupKey(it, by)
		const arr = buckets.get(k)
		if (arr) arr.push(it)
		else buckets.set(k, [it])
	}
	return Array.from(buckets.entries())
		.sort(([a], [b]) => a.localeCompare(b))
		.map(([key, items]) => ({ key, items }))
}

export const GROUP_BY_LABELS: Record<GroupBy, string> = {
	folder: 'Folder',
	prefix: 'Prefix',
	mediaType: 'Media type'
}

// Generic, project-neutral label for the workflow-stage axis.
export const WORKFLOW_STAGE_LABEL = 'Workflow stage'

import { describe, it, expect } from 'vitest'
import {
	folderOf,
	prefixOf,
	workflowStageOf,
	axisAvailable,
	groupItems,
	WORKFLOW_STAGE_LABEL
} from './grouping'

describe('folderOf', () => {
	it('returns parent dir for nested paths', () => {
		expect(folderOf('docs/helix/01-frame/prd.md')).toBe('docs/helix/01-frame')
	})
	it('returns "/" for top-level files', () => {
		expect(folderOf('README.md')).toBe('/')
	})
	it('handles leading slash', () => {
		expect(folderOf('/a/b/c.md')).toBe('/a/b')
	})
})

describe('prefixOf', () => {
	it('returns the first path segment', () => {
		expect(prefixOf('docs/helix/x.md')).toBe('docs')
	})
	it('strips leading slash', () => {
		expect(prefixOf('/library/personas/x.md')).toBe('library')
	})
	it('returns the whole name when there is no slash', () => {
		expect(prefixOf('README.md')).toBe('README.md')
	})
})

describe('workflowStageOf', () => {
	it('extracts a HELIX-style numbered stage segment', () => {
		expect(workflowStageOf('docs/helix/01-frame/prd.md')).toBe('frame')
		expect(workflowStageOf('docs/helix/04-build/spec.md')).toBe('build')
	})
	it('returns null when no stage segment is present', () => {
		expect(workflowStageOf('library/personas/x.md')).toBeNull()
		expect(workflowStageOf('README.md')).toBeNull()
	})
})

describe('axisAvailable', () => {
	it('is true when at least one path has a stage', () => {
		expect(axisAvailable(['README.md', 'docs/helix/02-design/x.md'])).toBe(true)
	})
	it('is false when no path has a stage', () => {
		expect(axisAvailable(['README.md', 'library/x.md'])).toBe(false)
	})
})

describe('groupItems', () => {
	const items = [
		{ path: 'docs/a.md', mediaType: 'text/markdown' },
		{ path: 'docs/b.md', mediaType: 'text/markdown' },
		{ path: 'src/x.svg', mediaType: 'image/svg+xml' }
	]
	it('groups by folder', () => {
		const groups = groupItems(items, 'folder')
		expect(groups.map((g) => g.key)).toEqual(['docs', 'src'])
		expect(groups[0].items).toHaveLength(2)
	})
	it('groups by mediaType', () => {
		const groups = groupItems(items, 'mediaType')
		expect(groups.map((g) => g.key)).toEqual(['image/svg+xml', 'text/markdown'])
	})
	it('groups by prefix', () => {
		const groups = groupItems(items, 'prefix')
		expect(groups.map((g) => g.key)).toEqual(['docs', 'src'])
	})
})

describe('label constants', () => {
	it('uses generic Workflow stage label', () => {
		expect(WORKFLOW_STAGE_LABEL).toBe('Workflow stage')
	})
})

